import{_ as e,o as i,c as s,S as t}from"./chunks/framework.C6RQlTYc.js";const c=JSON.parse('{"title":"概率分布与 Softmax","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_17-probability_softmax.md","filePath":"直击概念/17ai/s_ai_17-probability_softmax.md","lastUpdated":1778207238000}'),l={name:"直击概念/17ai/s_ai_17-probability_softmax.md"};function o(n,a,r,p,h,d){return i(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="概率分布与-softmax" tabindex="-1">概率分布与 Softmax <a class="header-anchor" href="#概率分布与-softmax" aria-label="Permalink to &quot;概率分布与 Softmax&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>LLM 的最终输出是一个概率分布——对于词汇表中的每个 token，模型给出一个<strong>概率值</strong>，表示该 token 作为下一个输出 token 的可能性。所有概率之和为 1。</p><p>Softmax 是将模型的原始输出（Logits）转换为概率分布的数学函数。</p><h2 id="logits" tabindex="-1">Logits <a class="header-anchor" href="#logits" aria-label="Permalink to &quot;Logits&quot;">​</a></h2><p>模型最后一层输出的原始数值称为 <strong>Logits</strong>（未归一化的对数概率）。每个 Logit 对应词汇表中的一个 token：</p><ul><li>正数越大 → 该 token 可能性越高</li><li>负数 → 该 token 可能性低</li><li>Logits 的范围是 (-∞, +∞)</li></ul><h2 id="softmax-公式" tabindex="-1">Softmax 公式 <a class="header-anchor" href="#softmax-公式" aria-label="Permalink to &quot;Softmax 公式&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>softmax(x)_i = exp(x_i) / Σ exp(x_j)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>作用三步</strong>：</p><ol><li><strong>exp(x)</strong> 将每个 Logit 转为正值（eˣ，x 越大值越大）</li><li>将所有 exp 值求和得到分母</li><li>每个 exp 除以总和，得到 0~1 之间的概率</li></ol><p><strong>示例</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>Logits:    [2.0, 1.0, 0.1]</span></span>
<span class="line"><span>exp:       [7.39, 2.72, 1.11]</span></span>
<span class="line"><span>softmax:   [0.66, 0.24, 0.10]    ← 概率分布</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="关键特性" tabindex="-1">关键特性 <a class="header-anchor" href="#关键特性" aria-label="Permalink to &quot;关键特性&quot;">​</a></h2><h3 id="归一化" tabindex="-1">归一化 <a class="header-anchor" href="#归一化" aria-label="Permalink to &quot;归一化&quot;">​</a></h3><p>所有输出概率之和恒为 1，构成合法的概率分布。</p><h3 id="指数放大" tabindex="-1">指数放大 <a class="header-anchor" href="#指数放大" aria-label="Permalink to &quot;指数放大&quot;">​</a></h3><p>exp 函数将 Logits 中的微小差异放大，让模型&quot;更自信&quot;地选出最可能的 token。GPT 的高 Logits 差值和低 Temperature 结合会产生确定性强的输出。</p><h3 id="温度调节" tabindex="-1">温度调节 <a class="header-anchor" href="#温度调节" aria-label="Permalink to &quot;温度调节&quot;">​</a></h3><p>在 Softmax 之前除以一个 Temperature 参数 T：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>softmax(x/T)_i = exp(x_i/T) / Σ exp(x_j/T)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>T &lt; 1：放大差异 → 更确定、保守</li><li>T &gt; 1：缩小差异 → 更随机、创造性</li><li>T = 1：原始分布</li></ul><h2 id="logprobs" tabindex="-1">Logprobs <a class="header-anchor" href="#logprobs" aria-label="Permalink to &quot;Logprobs&quot;">​</a></h2><p>API 中常见的 <code>logprobs</code> 参数，返回每个输出 token 的<strong>对数概率</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>logprobs_i = log(P(token_i))</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>值越接近 0 → 概率越高（概率 50% → logprobs ≈ -0.69）</li><li>值越负数 → 概率越低（概率 1% → logprobs ≈ -4.6）</li><li>用于评估模型对输出的&quot;置信度&quot;</li></ul><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>Softmax 为什么需要 exp？直接用原始值归一化不行吗？</li><li>如何通过概率分布判断模型是否&quot;不确定&quot;（多个 token 概率接近）？</li><li>Logprobs 为 -0.1 和 -5.0，哪个代表模型更确定？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://en.wikipedia.org/wiki/Softmax_function" target="_blank" rel="noreferrer">Softmax Function - Wikipedia</a></li><li><a href="https://platform.openai.com/docs/guides/text-generation/logprobs" target="_blank" rel="noreferrer">OpenAI API: Logprobs</a></li></ul>`,30)])])}const u=e(l,[["render",o]]);export{c as __pageData,u as default};
